/**
 * Release log shown in Settings → Version history.
 *
 * SOURCE OF TRUTH: the flat, newest-first {@link RELEASES} list below — one entry
 * per shipped version. The nested history tree is BUILT from it automatically by
 * {@link buildChangelogTree}: one named chapter per version era (newest first),
 * each auto-split into ~30-SP sub-groups (chapter → sub-group → release). Every SP
 * total is summed up the tree, and each sub-group is titled by its biggest release
 * and labelled with its version span — so adding ONE release to RELEASES re-shapes
 * the whole history and the SP-over-time graph on its own. No hand-nesting.
 *
 * To ship a release: prepend a `{ version, title, sp, note }` to RELEASES and bump
 * the on-screen <span class="version"> in index.html to match the newest version.
 */
export interface Release {
  version: string;
  /** 2–5 word label shown collapsed in the summary row. */
  shortTitle: string;
  /** Task code e.g. "DATA-12" or "CHART-5" — shown beside the version. */
  code: string;
  /** 5–15 word description, shown expanded in the body. */
  title: string;
  /** Story points. For a node with children this is the (auto-summed) total. */
  sp: number;
  /** Longer plain-language note, shown only when the row is expanded. */
  note: string;
  /** Optional extra bullet points, shown when expanded. */
  details?: string[];
  /** Task-code category (e.g. "EXR", "CHART"), used to auto-sum effort per part. */
  cat?: string;
  /** The Claude model that MADE this version (e.g. "Opus 4.8", "Haiku 4.5"),
   * shown as a chip and used to weight its € cost. Stamp every new release;
   * unstamped historical ones fall back to a breakpoint default
   * ({@link modelForRelease}). */
  model?: string;
  /** Nested child nodes (groups, or the leaf releases). Built automatically. */
  children?: Release[];
  /** Planned/not-yet-built: shown at the top with a "soon" tag, excluded from
   * the shipped release count, the SP total and the on-screen version. */
  soon?: boolean;
}

/** Planned, not-yet-built work — pinned at the top with a "soon" tag. */
