/** Build the history tree from the flat, newest-first RELEASES list: one named
 *  chapter per version era (newest first), each auto-split into ~30-SP sub-groups
 *  (a small chapter keeps its releases directly). All SP totals roll up the tree. */
export function buildChangelogTree(releases: Release[]): Release[] {
  const order: string[] = [];
  const byChapter = new Map<string, Release[]>();
  for (const r of releases) {
    const k = chapterKey(r.version);
    if (!byChapter.has(k)) { byChapter.set(k, []); order.push(k); }
    byChapter.get(k)!.push(r);
  }
  return order.map((k) => {
    const rels = byChapter.get(k)!;
    const chrono = [...rels].reverse();
    const subgroups: Release[] = bucketBySp(chrono, SUBGROUP_TARGET_SP).map((leaves) => {
      const kids = [...leaves].reverse();
      // shortTitle: short label of the highest-SP leaf in this bucket
      const topLeaf = leaves.reduce((best, r) => r.sp > best.sp ? r : best, leaves[0]!);
      const sgShort = topLeaf.shortTitle || headlineTitle(kids).split(/\s+/).slice(0, 4).join(" ");
      // title: the highest-SP leaf's full title (5–15 word medium description)
      const sgTitle = headlineTitle(kids);
      // note: cat breakdown + count
      const cats = [...new Set(kids.map(r => r.cat).filter(Boolean))].slice(0, 5).join(", ");
      const sgNote = `${kids.length} releases · ${cats || "mixed"}.`;
      return { version: spanLabel(kids), shortTitle: sgShort, code: "", title: sgTitle, sp: 0,
        note: sgNote, children: kids };
    });
    // bucketBySp walked chrono (oldest-first), so subgroups come out oldest-first;
    // flip to newest-first so children[0] is the newest era (what CURRENT_VERSION
    // and the version-history UI both assume). rels is already newest-first.
    const children = subgroups.length > 1 ? subgroups.reverse() : rels;
    return { version: k, shortTitle: CHAPTER_SHORT_TITLES[k] ?? "", code: "",
      title: CHAPTER_TITLES[k] ?? headlineTitle(rels), sp: 0,
      note: CHAPTER_NOTES[k] ?? `${rels.length} releases.`, children };
  });
}

export const CHANGELOG: Release[] = [SOON, ...buildChangelogTree(RELEASES)];

// SP rolls UP the tree: a node with children is the (rounded) sum of its
// children, computed here so the totals can never drift from the leaf numbers.
// Rounded to one decimal so fractional SP (0.1, 0.5) can't show a binary
// floating-point tail like 90.30000000000001.
function rollupSp(r: Release): number {
  if (r.children?.length) {
    r.sp = Math.round(r.children.reduce((s, c) => s + rollupSp(c), 0) * 10) / 10;
  }
  return r.sp;
}
for (const r of CHANGELOG) rollupSp(r);

/** Count the leaf releases (the actual shipped versions) under a node. */
export function countReleases(r: Release): number {
  if (r.soon) return 0;
  if (!r.children?.length) return 1;
  return r.children.reduce((n, c) => n + countReleases(c), 0);
}

/**
 * TOTAL story points across the whole shipped log — summed from the top-level
 * groups (each already the rounded sum of everything beneath it), so it's
 * never hand-maintained and updates on its own when a release is added.
 */
export const TOTAL_LOG_SP = Math.round(
  CHANGELOG.filter((r) => !r.soon).reduce((sum, r) => sum + r.sp, 0) * 10,
) / 10;

/**
 * Realistic € cost the project has ACTUALLY consumed so far — NOT the API list
 * price (that's a retail ceiling, far above what a flat-fee, shared, partially-used
 * subscription really spends). Derivation (owner's own estimate, 2026-06-13):
 *   • First ~3 weeks on the €90/mo plan, used only ~half the month's value at ~80%
 *     token utilisation and shared with others → ≈ €45 × 0.80 ≈ €36.
 *   • This week on the €180/mo plan, only a few % used so far → ≈ €4.
 *   → ≈ €40 total. Bump this as more weeks/usage accrue (and as the plan changes).
 */
export const PROJECT_COST_EUR = 40;

/**
 * € per story point: the whole project's real cost spread evenly across every
 * logged SP. A version / collection / era cost is just its SP × this rate, so the
 * numbers roll up the changelog tree exactly like SP does and the full-page total
 * always equals PROJECT_COST_EUR. Auto-tracks as SP grows (re-tune PROJECT_COST_EUR).
 */
export const COST_PER_SP_EUR = TOTAL_LOG_SP > 0 ? PROJECT_COST_EUR / TOTAL_LOG_SP : 0;

/** A node's flat € cost — rolled-up SP × the per-SP rate. Superseded for the
 * version-history display by the MODEL-AWARE {@link costForNode} below; kept as
 * the simple unweighted reference. */
export function costForSp(sp: number): number {
  return sp * COST_PER_SP_EUR;
}

/**
 * The MODEL that made each version — shown as a chip and used to WEIGHT its cost.
 * History wasn't recorded per-version, so: an explicit `model` stamp wins;
 * otherwise a breakpoint default — early work was almost all Opus, and Haiku
 * became the default for routine work at the "default-model-haiku" rule
 * (b.2.8.311.15), so versions from there on default to Haiku. New releases set
 * `model` directly.
 */
export const DEFAULT_MODEL_EARLY = "Opus 4.8";
export const DEFAULT_MODEL_RECENT = "Haiku 4.5";
const HAIKU_DEFAULT_FROM = "b.2.8.311.15";

/** Compare two b.MAJOR.MINOR.PATCH[.x] version strings; <0 if `a` is older. */
function cmpVersion(a: string, b: string): number {
  const pa = a.replace(/^b\./, "").split(".").map(Number);
  const pb = b.replace(/^b\./, "").split(".").map(Number);
  for (let i = 0; i < Math.max(pa.length, pb.length); i++) {
    const d = (pa[i] ?? 0) - (pb[i] ?? 0);
    if (d) return d;
  }
  return 0;
}

/** The model label for a leaf release — explicit stamp, else breakpoint default. */
export function modelForRelease(r: Release): string {
  if (r.model) return r.model;
  return cmpVersion(r.version, HAIKU_DEFAULT_FROM) >= 0 ? DEFAULT_MODEL_RECENT : DEFAULT_MODEL_EARLY;
}

/** Distinct models under a node — one entry for a leaf, the full set for a group
 *  (so an era can read "Mixed" when its versions span more than one model). */
export function modelsUnder(r: Release): string[] {
  if (r.soon) return [];
  if (!r.children?.length) return [modelForRelease(r)];
  return [...new Set(r.children.flatMap(modelsUnder))];
}

/**
 * Relative € weight per model, anchored to OUTPUT price ($/MTok — the dominant
 * cost) and normalised to Opus = 1.0: Opus 25 · Sonnet 15 · Haiku 5 · Fable 50.
 * So a Haiku version costs ~1/5 of an Opus one of equal SP. Only the
 * DISTRIBUTION of cost across versions is model-weighted — the grand total stays
 * pinned to PROJECT_COST_EUR. (Rates verified 2026-06-13: Opus 4.8 $5/$25,
 * Haiku 4.5 $1/$5 per MTok.) */
const MODEL_OUTPUT_PRICE: Record<string, number> = { Opus: 25, Sonnet: 15, Haiku: 5, Fable: 50, Mythos: 50 };
function modelWeight(model: string): number {
  const family = model.split(/\s+/)[0] ?? "Opus"; // "Opus 4.8" -> "Opus"
  return (MODEL_OUTPUT_PRICE[family] ?? MODEL_OUTPUT_PRICE.Opus!) / MODEL_OUTPUT_PRICE.Opus!;
}

/** RECENCY effort multiplier (owner: "the last 100 SP at double value — it's been
 *  slower and harder"). The most-recent RECENT_SP_WINDOW story-points (walking the log
 *  newest-first) are valued at RECENCY_EFFORT_MULT× in the version-history COST
 *  distribution. The grand total stays pinned to PROJECT_COST_EUR — this only shifts the
 *  per-version € SHARE toward recent work, so a recent update reads ~2× the € it
 *  otherwise would and older work proportionally less. (Cost-method refinement; the SP
 *  grades themselves are unchanged. See docs/cost-model.md.) */
export const RECENCY_EFFORT_MULT = 2;
export const RECENT_SP_WINDOW = 100;
const RECENT_VERSIONS: Set<string> = (() => {
  const s = new Set<string>();
  let acc = 0;
  for (const r of RELEASES) {            // RELEASES is newest-first
    if (r.soon) continue;
    if (acc >= RECENT_SP_WINDOW) break;  // covered the most-recent 100 SP
    s.add(r.version);
    acc += r.sp;
  }
  return s;
})();
function recencyWeight(r: Release): number {
  return RECENT_VERSIONS.has(r.version) ? RECENCY_EFFORT_MULT : 1;
}

/** Σ over leaves of sp × model-weight × recency-weight — the denominator that keeps the
 *  weighted total equal to PROJECT_COST_EUR. */
const WEIGHTED_SP_TOTAL = RELEASES.reduce(
  (s, r) => (r.soon ? s : s + r.sp * modelWeight(modelForRelease(r)) * recencyWeight(r)), 0);
/** € per weighted story-point, so Σ of every leaf's cost === PROJECT_COST_EUR. */
export const EUR_PER_WEIGHTED_SP = WEIGHTED_SP_TOTAL > 0 ? PROJECT_COST_EUR / WEIGHTED_SP_TOTAL : 0;

/** A node's MODEL-AWARE € cost: a leaf is sp × model-weight × recency-weight × rate; a
 *  group is the sum of its children, so it rolls up the tree exactly like SP does. */
export function costForNode(r: Release): number {
  if (r.soon) return 0;
  if (r.children?.length) return r.children.reduce((s, c) => s + costForNode(c), 0);
  return r.sp * modelWeight(modelForRelease(r)) * recencyWeight(r) * EUR_PER_WEIGHTED_SP;
}

/** The on-screen version: the newest actual leaf — descend the first child of
 * the newest shipped group until there are no more children. */
let newest = CHANGELOG.find((r) => !r.soon)!;
while (newest.children?.length) newest = newest.children[0]!;
export const CURRENT_VERSION = newest.version;

/** The modified-Fibonacci SP scale — the only allowed grades, no in-between. */
export const SP_SCALE = [1, 2, 3, 5, 8, 13, 20, 30, 50, 80, 130, 200] as const;

/** Snap an exact story-point count to the nearest value on {@link SP_SCALE}
 * (so a fib-SP is only ever 10, 20, 30, … never an in-between number). */
export function fibSp(n: number): number {
  let best = SP_SCALE[0] as number;
  for (const v of SP_SCALE) if (Math.abs(v - n) < Math.abs(best - n)) best = v;
  return best;
}

/**
 * Per-section EFFORT shown under the title — the EXACT story points spent on each
 * part (estimated by reading the whole history). Each part also carries a
 * Fibonacci grade ({@link fibSp}) so it reads both precisely and on the scale.
 */
export interface Component { name: string; sp: number; }

/** SP per task-code category under a node, sorted by SP. The category is the
 *  code straight from each release's git commit ({@link Release.cat}, e.g.
 *  "EXR", "CHART", "META") — so every grouping shows which tasks its story
 *  points came from. */
export function categoryBreakdown(node: Release): Component[] {
  const sums = new Map<string, number>();
  const walk = (r: Release) => {
    if (r.soon) return;
    if (r.children?.length) r.children.forEach(walk);
    else sums.set(r.cat ?? "?", (sums.get(r.cat ?? "?") ?? 0) + r.sp);
  };
  walk(node);
  return [...sums.entries()]
    .map(([name, sp]) => ({ name, sp: Math.round(sp * 10) / 10 }))
    .sort((a, b) => b.sp - a.sp);
}

/** Whole-log effort per task-code category — summed AUTOMATICALLY from every
 *  release's {@link Release.cat}; updates itself whenever a release is added. */
export function computeComponents(): Component[] {
  const sums = new Map<string, number>();
  for (const r of RELEASES) {
    if (r.soon) continue;
    const k = r.cat ?? "?";
    sums.set(k, (sums.get(k) ?? 0) + r.sp);
  }
  return [...sums.entries()]
    .map(([name, sp]) => ({ name, sp: Math.round(sp * 10) / 10 }))
    .sort((a, b) => b.sp - a.sp);
}
export const COMPONENTS: Component[] = computeComponents();

/** Whole-site EXACT story points (sum of every category) and its Fibonacci grade. */
export const WEBSITE_EXACT_SP = Math.round(COMPONENTS.reduce((s, c) => s + c.sp, 0) * 10) / 10;
export const WEBSITE_SP = fibSp(WEBSITE_EXACT_SP);

